from flask import Flask, request, jsonify
import psycopg2
from psycopg2.extras import RealDictCursor

app = Flask(__name__)

# Database connection settings
DB_HOST = 'your_host'
DB_NAME = 'your_database'
DB_USER = 'your_username'
DB_PASSWORD = 'your_password'

@app.route('/query', methods=['POST'])
def query():
    try:
        # Get table and column names from request body
        data = request.json
        table_name = data.get('table')
        columns = data.get('columns')
        filters = data.get('filters')

        if not table_name or not columns or not filters:
            return jsonify({'error': 'Missing required parameters'}), 400

        # Validate column names
        valid_columns = ['column1', 'column2']  # Replace with actual column names
        for col in columns:
            if col not in valid_columns:
                return jsonify({'error': f'Invalid column name: {col}'}), 400

        # Build SQL query dynamically
        query = f"SELECT {', '.join(columns)} FROM {table_name}"
        conditions = []
        params = []

        for filter_key, filter_value in filters.items():
            if filter_value:
                conditions.append(f"{filter_key} = %s")
                params.append(filter_value)

        if conditions:
            query += " WHERE " + " AND ".join(conditions)
            params.extend([None] * (len(columns) - len(filters)))

        # Execute SQL query
        conn = psycopg2.connect(
            host=DB_HOST,
            database=DB_NAME,
            user=DB_USER,
            password=DB_PASSWORD
        )
        cur = conn.cursor(cursor_factory=RealDictCursor)

        try:
            cur.execute(query, params)
            result = cur.fetchall()
            return jsonify(result), 200
        except psycopg2.Error as e:
            return jsonify({'error': str(e)}), 500

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)